"use client";
import Loader from "@/components/molecules/Loader";
import LoaderOverlay from "@/components/molecules/LoaderOverlay";
import UpdateRoleForm from "@/components/blocks/admin-section/roles/UpdateRoleForm";
import { Card, CardContent } from "@/components/ui";
import { Routes } from "@/config/routes";
import { useRolesQueryById } from "@/modules/admin-section/roles/roles.action";
import { Users } from "lucide-react";
import { useTranslations } from "next-intl";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useState } from "react";
import CardSkletonLoader from "@/components/molecules/CardSkletonLoader";

const EditRole = ({ ID }: any) => {
  const t = useTranslations();
  const pathname = usePathname();
  const { Role, refetch, isPending } = useRolesQueryById(ID);
  const [isLoading, setIsLoading] = useState(false);
  useEffect(() => {
    setIsLoading(false);
  }, [pathname]);

  useEffect(() => {
    if (isLoading) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }
    return () => {
      document.body.style.overflow = "auto";
    };
  }, [isLoading]);
  useEffect(() => {
    refetch();
  }, [refetch]);

  if (!ID) {
    return (
      <div className="mt-10">
        <h1 className="text-xl text-red-500">{t("common.invalid_id")}</h1>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <LoaderOverlay isLoading={isLoading} />
      <Card>
        <CardContent className="flex items-center justify-between p-2 md:p-4">
          <div className="flex items-center justify-start md:justify-center gap-2">
            <Users />
            <h1 className="text-lg md:text-2xl font-semibold text-black dark:text-white flex items-center gap-2">
              {t("label.edit_role")}
            </h1>
          </div>
          <div className="flex">
            <p className="text-sm font-semibold text-blue-500 hover:text-white dark:text-[#93c5fd] dark:hover:text-white  bg-blue-100 hover:bg-blue-500 py-2 px-4 rounded flex items-center gap-2">
              <Link
                className=""
                href={Routes.roles}
                onClick={(e) => {
                  const isNewTab = e.metaKey || e.ctrlKey || e.button === 1;

                  if (!isNewTab) {
                    setIsLoading(true);
                  }
                }}
              >
                {t("label.roles")}
              </Link>
            </p>
          </div>
        </CardContent>
      </Card>
      {isPending || !Role ? (
        <CardSkletonLoader />
      ) : (
        <>
          <UpdateRoleForm data={Role} isPending={isPending} />
        </>
      )}
    </div>
  );
};

export default EditRole;
